import{_ as a,o as s,c as t,ag as l}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"Realtime Capabilities","description":"","frontmatter":{},"headers":[],"relativePath":"realtime.md","filePath":"realtime.md"}'),n={name:"realtime.md"};function o(r,e,i,p,c,d){return s(),t("div",null,[...e[0]||(e[0]=[l(`<h1 id="realtime-capabilities" tabindex="-1">Realtime Capabilities <a class="header-anchor" href="#realtime-capabilities" aria-label="Permalink to &quot;Realtime Capabilities&quot;">​</a></h1><p>LinkedQL brings reactivity to the database layer, letting queries directly drive application state.</p><p>On any given database, LinkedQL lets you have live queries as a first-class capability, and directly supports table-level subscriptions.</p><hr><h2 id="meet-live-queries" tabindex="-1">Meet Live Queries <a class="header-anchor" href="#meet-live-queries" aria-label="Permalink to &quot;Meet Live Queries&quot;">​</a></h2><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">    p.title,</span></span>
<span class="line"><span style="color:#C3E88D;">    p.category,</span></span>
<span class="line"><span style="color:#C3E88D;">    author ~&gt; { name, email } AS author</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM posts AS p</span></span>
<span class="line"><span style="color:#C3E88D;">  WHERE p.published = true</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY p.created_at DESC</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>No need for a separate subscription layer (like a GraphQL server) in front of your database. <strong>Your query is the subscription.</strong></p><p><code>result</code> is the same shape as a regular query result but self-updating as the database changes over time.</p><p>Updates are pushed from the database to the client—no polling, no manual subscriptions:</p><ul><li>automatically stays current over time</li><li>directly powers reactivity across the app</li></ul><hr><h2 id="meet-changefeeds-direct-table-level-subscriptions" tabindex="-1">Meet Changefeeds (Direct Table-Level Subscriptions) <a class="header-anchor" href="#meet-changefeeds-direct-table-level-subscriptions" aria-label="Permalink to &quot;Meet Changefeeds (Direct Table-Level Subscriptions)&quot;">​</a></h2><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> unsubscribe </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">wal</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">subscribe</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> public</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">] </span><span style="color:#89DDFF;">},</span><span style="color:#89DDFF;"> (</span><span style="color:#BABED8;font-style:italic;">commit</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#BABED8;">  console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">commit</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Sometimes you need changes at the table or commit level, not a query result.</p><p><code>db.wal.subscribe()</code> exposes commit-level events from the database’s change stream::</p><ul><li>PostgreSQL&#39;s Write Ahead Log (WAL)</li><li>MySQL/MariaDB&#39;s Binary Log (Binlog)</li><li>FlashQL&#39;s Write Ahead Log (WAL)</li></ul><p>It&#39;s especially useful for replication flows, synchronization logic, and downstream processors.</p><hr><h2 id="the-broader-idea" tabindex="-1">The Broader Idea <a class="header-anchor" href="#the-broader-idea" aria-label="Permalink to &quot;The Broader Idea&quot;">​</a></h2><p>In a traditional stack, reactivity is assembled from multiple layers:</p><ul><li>the database</li><li>a subscription server and/or a sync engine</li><li>app-level invalidation logic</li><li>client caches or replicas</li></ul><p>LinkedQL pushes the behaviour itself into where the data already lives: the database, collapsing that stack back into the database layer.</p><hr><h2 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Capability</th><th style="text-align:left;">What It Adds</th><th style="text-align:left;">Docs</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Live Queries</strong></td><td style="text-align:left;">Queries that work in live mode and return real-time results</td><td style="text-align:left;"><a href="/realtime/live-queries">Live Queries</a></td></tr><tr><td style="text-align:left;"><strong>Changefeeds</strong></td><td style="text-align:left;">Direct table-level commit stream</td><td style="text-align:left;"><a href="/realtime/changefeeds">JSON Literals</a></td></tr></tbody></table>`,25)])])}const u=a(n,[["render",o]]);export{h as __pageData,u as default};
